INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_25', 'variant_5', 2, '– Srinagar – Sonamarg – Srinagar: Today you embark on a full day excursion to th', '– Srinagar – Sonamarg – Srinagar: Today you embark on a full day excursion to the picturesque meadow of gold’ Sonamarg. Sonamarg is the last stop of Kashmir district. From here starts the territory of ladakh. Situated at an altitude of 2743 mt above sea level. The fast-flowing Sindh River makes it popular for trout and masher fishing in summer. You can opt for a pony ride (Own cost) to one of the Thajiwas glaciers for some fun in snow and ice (by your own payment). You can also visit Zero Point/') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_26', 'variant_5', 3, '– Srinagar – Pahalgam – Srinagar', '– Srinagar – Pahalgam – Srinagar. After breakfast drive to Pahalgam (The valley of shepherds). Which is about 96 kms from Srinagar, which will be covered in the app. 3 hours. You Can visit the saffron fields of pampore, Awantipura Ruins (1100 years old temple of Lord Vishnu built by the King Awantivarman), Mattan Temple on En-route. Drive through the pine forests. Arrive at Pahalgam and enjoy Lidder stream. After You can hire a union car (at your own cost) visit Aru, betaab valley and chandanwar') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_27', 'variant_5', 4, '– Srinagar –Gulmarg - Srinagar : After breakfast check out from the hotel in Sri', '– Srinagar –Gulmarg - Srinagar : After breakfast check out from the hotel in Srinagar drive to Gulmarg (2440 Meters above Sea level). It is one of the most beautiful hill stations and also called “Meadows of Flower”. It has the world’s highest golf course and Gulmarg is also famous for winter sports like skiing. On arrival and after refreshment one can visit Jai Jai Shiv Shankar Temple and also enjoy a Gondola ride (Cable car, own cost) from Gulmarg to Kongdori and affarwat. Evening return dinne') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
