INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_30', 'variant_6', 2, 'SRINAGAR TO GULMARG - 52 Kms – 2 Hrs approx:
                    After breakfast', 'SRINAGAR TO GULMARG - 52 Kms – 2 Hrs approx:
                    After breakfast you will proceed for a full day excursion to Gulmarg, Meadow of Flowers(66kms / 2 hr) situated at an altitude of 2730 meters, full day at leisure to take the leisurely walks on the lush green meadows of flowers with a backdrop of the snow capped mountains. Enjoy a pony ride or Gondola ride (rope way at your own cost) to Khilanmarg at your own cost- Overnight in the Gulmarg.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
