INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_336', 'variant_57', 1, 'Delhi to Shimla(350 Kms', 'Delhi to Shimla(350 Kms. 7/8 Hrs.)- Chandigarh to Shimla(120 Kms. 4 Hrs. approx.): Upon arrival Morning at Delhi/Chandigarh Airport/ Railways station and drive towards Shimla. Shimla, a very popular holiday-retreat, is well-known for its Victorian architecture, which is reflected in certain areas of the Mall and The Ridge. Upon arrival at Shimla, Overnight at the hotel.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_337', 'variant_57', 2, 'After breakfast at the hotel, proceed for a half day excursion to Kufri (2500mts', 'After breakfast at the hotel, proceed for a half day excursion to Kufri (2500mts). Kufri is also renowned for other adventure activities such as skiing, tobogganing (sliding downhill on a sled), etc. You can also take a hike or a Pony up to Mashu Peak(own cost-direct payment basis). Afternoon: Guests will be dropped at the Shimla elevator & explore by themselves. Attractions of the mall road include Shimla Church, Scandal Point, Gaiety Theater, Town hall, Jaku Temple & shopping. Overnight at the') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
