INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_351', 'variant_58', 7, 'Dharamshala To Dalhousie(125 Kms', 'Dharamshala To Dalhousie(125 Kms. 4 Hrs. approx.): After breakfast, Towards Dalhousie after doing the local sightseeing of Places which includes, His holiness Dalai lama residence & Tsugalkhang at Mcleodganj, St. john’s church in the wilderness (Built in 1853),War memorial, Bhagsunath temple and Dal Lake, Norbulingka, Gyuto Rameda Tantric Monastery. Reach Dalhousie in the evening. Stay at a hotel.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_352', 'variant_58', 8, 'Dalhousie has been named after the British Governor – General of the l9th centur', 'Dalhousie has been named after the British Governor – General of the l9th century, Lord Dalhousie. Surrounded by varied vegetation – pines, dodders, oaks and flowering rhododendrons. Local sightseeing of Dalhousie includes visit to Panjipula, Subhash Baoli and excursion to Khajjiar 24 km from Dalhousie surrounded by thick Deodar forest. Drive from Dalhousie to Khajjiar is awesome. Stay at a hotel.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
