INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_365', 'variant_62', 1, 'Arrive Srinagar | Srinagar Local Sightseeing', 'Arrive Srinagar | Srinagar Local Sightseeing. Welcome to Srinagar, the Lake City. On arrival at Srinagar Airport, begin your Kashmir Tour. You will be transferred to the Hotel. Proceed on a city tour visiting the Shankar Acharya temple situated on the highest hill of Srinagar, the famous Mughal Gardens – Chashmashahi, Nishat & Shalimar. These gardens were Mughal Emperor concepts of Paradise and today these are popular picnic spots. Visit Hazratbal Dargah Also. Overnight stay in a hotel.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_366', 'variant_62', 2, '– Srinagar – Pahalgam – Srinagar After breakfast drive to Pahalgam (The valley o', '– Srinagar – Pahalgam – Srinagar After breakfast drive to Pahalgam (The valley of shepherds). Which is about 96 kms from Srinagar, which will be covered in the app. 3 hours. You Can visit the saffron fields of pampore, Awantipura Ruins (1100 years old temple of Lord Vishnu built by the King Awantivarman), Mattan Temple, on En-route. Drive through the pine forests. Arrive at Pahalgam and You can go for Pony ride, visit Kashmir Valley, Dabyan, Baisaran/ mini-Switzerland, Denow Valley Waterfall (At') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_367', 'variant_62', 3, '– Srinagar –Gulmarg– Srinagar, After breakfast check out from the hotel in Srina', '– Srinagar –Gulmarg– Srinagar, After breakfast check out from the hotel in Srinagar drive to Gulmarg (2440 Meters above Sea level). It is one of the most beautiful hill stations and also called “Meadows of Flower”. It has the world’s highest golf course and Gulmarg is also famous for winter sports like skiing. On arrival and after refreshment one can visit Jai Jai Shiv Shankar Temple and also enjoy a Gondola ride (Cable car, own cost) from Gulmarg to Kongdori and affarwat. Evening return dinner ') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
