INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_386', 'variant_65', 2, 'Kathmandu Sightseeing
Today, engage yourself in Kathmandu’s rich cultural herita', 'Kathmandu Sightseeing
Today, engage yourself in Kathmandu’s rich cultural heritage with a full-day
sightseeing tour. Begin with a visit to Pashupatinath Temple and Gujeshowri Temple.
Continue to Boudhanath Stupa, one of the largest stupas in the world and a UNESCO
World Heritage Site. In the afternoon, explore Swayambhunath Stupa, also known as
the Monkey Temple, and finish the day at Kathmandu Durbar Square, a historic
palace square that showcases traditional Nepalese architecture.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_387', 'variant_65', 3, 'Early Morning Trip to Nagarkot and Drive to Pokhara via Manakamana
Early in the ', 'Early Morning Trip to Nagarkot and Drive to Pokhara via Manakamana
Early in the morning, drive to Nagarkot to witness a breathtaking sunrise over the
Himalayas. After enjoying the stunning views, return to your hotel in Kathmandu for
breakfast. Following breakfast, embark on a scenic drive to Manakamana Temple,
accessible by a cable car ride that offers spectacular views of the surrounding
landscape. After visiting the temple, continue your journey to Pokhara. Upon arrival,
check into your hotel') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
