Valley.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
