INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_460', 'variant_72', 4, 'Gangtok – Tsomgo Lake & Baba Mandir (EAST SIKKIM)- This morning after breakfast ', 'Gangtok – Tsomgo Lake & Baba Mandir (EAST SIKKIM)- This morning after breakfast we shall head for a full day excursion to three prominent sites – Tsomgo Lake, Nathula Pass and Baba Mandir. We start driving up above Gangtok through intricate winding road along the mystical environs and reach an enchanting Tsomgo lake after about one and half hours. A lake is nestled amidst high peaks at an altitude of 12,400 ft. On winters, you will be able to witness the lake in a frozen state. Spend some time e') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
