INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_560', 'variant_83', 4, 'After breakfast go for a full day excursion to Solang valley day tour, Solang Va', 'After breakfast go for a full day excursion to Solang valley day tour, Solang Valley with its rolling meadows, ski slopes and paragliding activities ( Own cost-Direct payment basis),  Overnight stay at the hotel. * Optional Tour with extra paid: Atul tunel, Sissu, Rohtang pas') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
