INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_564', 'variant_85', 1, 'Arrive NJP Railway Station/Bagdogra Airport To Gangtok', 'Arrive NJP Railway Station/Bagdogra Airport To Gangtok. Meet and greet on arrival & transfer to Gangtok(5500 FT.) the capital of Sikkim – The land of the Pristine and un-spoilt natural beauty with alpine landscapes and thick luxuriant forests,River and peaceful lakes. Evening free for own activities. Rest of the day at leisure.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
