INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_569', 'variant_86', 1, 'IXB to Gangtok (120 kms', 'IXB to Gangtok (120 kms. 4,5 hrs. approx.): Upon your arrival at Bagdogra Airport, you will have an assisted transfer to Gangtok. Complete the check-in formalities at the hotel. The rest of the day is free at leisure. Overnight at the hotel.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_570', 'variant_86', 2, 'Gangtok sightseeing: After breakfast, proceed for a day trip to Tsomgo Lake', 'Gangtok sightseeing: After breakfast, proceed for a day trip to Tsomgo Lake. Also known as Changu Lake, this glacial lake is a popular tourist attraction and is located on the road towards the Nathu La pass. The next visit is to Baba Mandir. This shrine is built in the memory of a brave Indian soldier, Harbhajan Singh, who died during the war near the Nathu La Pass. Return to Gangtok. The evening is free for shopping activities. Overnight stay at the hotel. Optional tour to Nathula Pass (Alt 140') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_571', 'variant_86', 3, 'Gangtok to Darjeeling (115 kms', 'Gangtok to Darjeeling (115 kms. 4 hrs. approx.): After breakfast, proceed for a half-day sightseeing tour of Gangtok covering Banjhakri Falls, Cottage Industry and Handicraft Center, Flower show, Dro-dul Chorten & Institute of Tibetology. Afternoon drive to Darjeeling (7,100 ft.). On arrival, check in to your hotel. Overnight stay at Darjeeling.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_572', 'variant_86', 4, 'Darjeeling sightseeing: Early morning, leave to view the sunrise at Tiger Hill', 'Darjeeling sightseeing: Early morning, leave to view the sunrise at Tiger Hill. This is a major attraction amongst the tourists. After breakfast, visit Padmaja Naidu Zoological Park (Closed on Thursday), Himalayan Mountaineering Institute (Closed on Thursday), and Tea garden in the undulating valleys to view the scenic landscape of tea plucking and processing.
                    Visit Ghoom Monastery & Batasia Loop. Also, visit the Japanese Temple dedicated to Lord Buddha and constructed in 197') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
