INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_589', 'variant_89', 1, 'Kozhikode to Wayanad: On arriving at the Kozhikode railway station/ airport, mee', 'Kozhikode to Wayanad: On arriving at the Kozhikode railway station/ airport, meet our representative. He helps you with an assisted transfer to Wayanad, by road, which takes around 3 hours. Upon reaching the well-known Vythiri Resort, one of the most popular treehouse resorts in Wayanad, which is positioned above the thick canopies of the rainforest. Check into your treehouse. Vythiri resort is an eco-friendly resort that has treehouses and cottages, which are built using local materials along w') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_590', 'variant_89', 2, 'Wayanad sightseeing: After breakfast, get ready for a city tour of Wayand', 'Wayanad sightseeing: After breakfast, get ready for a city tour of Wayand. You visit the placid Lake Pookot- a freshwater lake where the visitors can enjoy boat riding, amid fresh air and green ambiance. Next, you visit the three-tiered Soojipara waterfalls that are also known as Sentinel Rock Waterfalls. Thereafter, your next visit is to the largest dam of India, Bansura Sagar dam, which is also the second largest earth dam in Asia. The surroundings of the dam are tranquil and breathtaking. Con') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
