INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_592', 'variant_90', 1, 'Bangalore to Coorg: After arriving in Bangalore, you are escorted to be moved to', 'Bangalore to Coorg: After arriving in Bangalore, you are escorted to be moved to Coorg. Once you reach there, you check- in at the hotel and spend the rest of the day at leisure, in the comfort of the hotel and later retire for the night.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_593', 'variant_90', 2, 'Coorg Sightseeing:
                    Your day has been planned out for the sig', 'Coorg Sightseeing:
                    Your day has been planned out for the sightseeing tour in Coorg for half day, directly after breakfast you leave. You visit the coffee plantations, and the orchards; there is a Fort on top of a hill that overlooks the town. There is a temple of Lord Omkareswara, the design in the temple is appealing. Later in the evening you return to the hotel for an overnight stay.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
