INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_595', 'variant_90', 4, 'Mysore to Wayanad: You drive to Wayanad after breakfast and check out of the hot', 'Mysore to Wayanad: You drive to Wayanad after breakfast and check out of the hotel. After reaching Wayanad, you check in at the hotel and spend the rest of the day at leisure and later, sleep over for the night.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
