INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_598', 'variant_91', 1, 'Bangalore to Mysore: You first arrive at the Bangalore airport, where you will b', 'Bangalore to Mysore: You first arrive at the Bangalore airport, where you will be received by the representative. Then, you head towards Mysore, it takes about 3 hours to drive there. Once you are there, you check- in at the hotel. Later, you visit the beautiful Brindavan Garden and return back to the hotel for dinner and an overnight stay.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_599', 'variant_91', 2, 'Mysore to Ooty: You check – out of the hotel in the morning, after your breakfas', 'Mysore to Ooty: You check – out of the hotel in the morning, after your breakfast. You go out for a sightseeing tour in Mysore; visit the Chamundi Hills and the Bull Temple. Lastly, you visit the Mysore Palace and proceed to Ooty. On the way you stop to see the Pykara Lake, which offers a great view. Once you reach Ooty, you check- in at the hotel, enjoy your dinner, and later retire for the night.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_600', 'variant_91', 3, 'Ooty sightseeing: Your day is planned out for Ooty sightseeing, so to do that yo', 'Ooty sightseeing: Your day is planned out for Ooty sightseeing, so to do that you leave right away after breakfast. You visit Doddabetta Peak, Botanical Garden and later visit Charing Cross, You can indulge in shopping and a nice lunch in the town. Next, you visit the Tea Museum and the Ooty lake where you can enjoy the boat ride. Later, in the evening, you return to the hotel for an overnight stay.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_601', 'variant_91', 4, 'Ooty to Kodaikanal: You check out of the hotel in the morning after breakfast an', 'Ooty to Kodaikanal: You check out of the hotel in the morning after breakfast and head towards Coonoor. There is also a toy train ride that takes you to Coonoor, you can opt for that. After the exciting train journey, you visit the Sim’s park, dolphin’s nose and lamb’s rock. You further drive to Kodaikanal, and on reaching there you check in at the hotel where dinner will be served and you can retire for the night.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
INSERT INTO "ItineraryDay" ("id", "variantId", "day", "title", "description") VALUES ('day_602', 'variant_91', 5, 'Kodaikanal sightseeing: After breakfast, you go out for kodaikanal sightseeing, ', 'Kodaikanal sightseeing: After breakfast, you go out for kodaikanal sightseeing, the place is covered in greenery and the view it offers is spectacular. Visit the Pillar Rock and the Coakers Walk. Later you can enjoy boating at the Kodai lake and then, return to the hotel. Have dinner and stay overnight.') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "variantId" = EXCLUDED."variantId", "day" = EXCLUDED."day", "title" = EXCLUDED."title", "description" = EXCLUDED."description";
