-- Table: FAQ
INSERT INTO "FAQ" ("id", "question", "answer", "sortOrder") VALUES (1, 'What types of trips does Mother India Tour Travels offer?', 'We specialize in customized domestic and international tour packages, including heritage tours, luxury cruises, desert safaris, wildlife tours, and spiritual retreats tailored for individuals, families, and groups.', 0) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "sortOrder" = EXCLUDED."sortOrder";
INSERT INTO "FAQ" ("id", "question", "answer", "sortOrder") VALUES (2, 'What is your cancellation or refund policy?', 'We offer flexible cancellation. Cancellations made 30 days or more prior to departure are eligible for a full refund minus nominal administrative fees. Cancellations between 15-29 days are charged 25%, and cancellations under 14 days are subject to standard cancellation charges depending on bookings made.', 1) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "sortOrder" = EXCLUDED."sortOrder";
INSERT INTO "FAQ" ("id", "question", "answer", "sortOrder") VALUES (3, 'Are Mother India Tour Travels''s trips safe and well-guided?', 'Yes, absolutely! All our tours are accompanied by professional, licensed local guides, and we use certified transport partners with experienced drivers to ensure your complete safety, comfort, and peace of mind.', 2) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "sortOrder" = EXCLUDED."sortOrder";
INSERT INTO "FAQ" ("id", "question", "answer", "sortOrder") VALUES (4, 'Can I customize my travel itinerary?', 'Yes, absolutely! We specialize in crafting tailor-made itineraries designed around your preferences, travel pace, and budget. Our travel experts will work with you to design the perfect custom holiday.', 3) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "sortOrder" = EXCLUDED."sortOrder";
INSERT INTO "FAQ" ("id", "question", "answer", "sortOrder") VALUES (5, 'How do I book a trip?', 'Booking is simple! You can use our search bar to find packages and send an inquiry, call or WhatsApp our hotline at {phone}, or email us at {email}. Our representative will contact you within 24 hours to finalize your plans.', 4) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "sortOrder" = EXCLUDED."sortOrder";

