-- Table: Company
INSERT INTO "Company" ("id", "name", "tagline", "website", "phones", "email", "address", "timezone", "schedule", "exceptions", "socialMedia", "certifications", "about", "whatsappNumber", "googleAnalytics", "googleTagManager", "latitude", "longitude") VALUES (1, 'Mother India Tour Travels', 'Explore India with Trusted Tours', 'https://www.motherindiatourtravels.com', '["+919810140121","+919971053881"]', 'tourtravelsmotherindia@gmail.com', 'B63/B63A, New Jankipuri, Uttam Nagar, New Delhi - 110059', 'Asia/Kolkata', '[{"days":["mon","tue","wed","thu","fri"],"hours":[{"open":"09:00","close":"20:00"}]},{"days":["sat","sun"],"hours":[{"open":"09:00","close":"20:00"}]}]', '[]', '{"facebook":"https://www.facebook.com/driverandcarhire","instagram":"https://www.instagram.com/tour_operator_delhi/","twitter":"https://x.com/TravelsZ","linkedin":"https://www.linkedin.com/in/mother-india-tour-travels-b691b122/","pinterest":"https://in.pinterest.com/Mother_India_Tour_Delhi1/","whatsapp":"https://wa.me/9810140121"}', '["MSME Certified","ISO 9001:2015"]', '{"footer": "Mother India Tour Travels is a trusted tour and travel agency based in Delhi, India. We specialize in customized domestic and international tour packages for individuals, families, and groups. With years of experience, we have served thousands of satisfied customers from around the world.", "header": { "badge": "MOTHER INDIA • DISCOVER • EXPLORE • EXPERIENCE", "title": "Crafting Unforgettable Journeys Together", "description": "At Mother India Tour Travels, we believe in the magic of exploration and the power of personalized travel. With a dedicated team of tourism experts and a deep commitment to excellence, we curate tours that bring your dream vacations to life.", "image": "https://motherindiatourtravels.com/assests/about.jpeg", "introText": "We have vast experience in the Tour and Travel Industry. With a corporate vision and mission reflected in our goals, we have developed a respected position by delivering customized solutions for the specific travel needs of our clients. We successfully serve individuals, families, schools, colleges, educational institutes, and corporate groups, ensuring unforgettable experiences across the country and the world.", "stats": [ { "value": "20+", "label": "Years Experience" }, { "value": "10k+", "label": "Happy Travelers" }, { "value": "500+", "label": "Corporate & School Groups" }, { "value": "50+", "label": "Indian Destinations" } ] }, "mission": { "title": "Our Mission", "description": "We are committed to establishing a brand quality that is trusted. We provide reliable and quality travel solutions to meet all implied needs of our clients and achieve client satisfaction through highly motivated workforce involvement and a quality management system. We strive to provide services that not only satisfy our clients but also encourage them to repeat their tours and travels in India. We also strive to provide authentic experiences for visitors by developing and expanding the diversity and quality of our services.", "items": [ "Establishing Brand Quality & Trust", "Exceeding Client Expectations at Every Step", "Authentic Travel Experiences Across India", "Continuous Workforce Growth & Development" ], "images": [ "https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&w=800&q=80", "https://images.unsplash.com/photo-1501555088652-021faa106b9b?auto=format&fit=crop&w=600&q=80" ] }, "vision": { "title": "Our Vision", "description": "We seek a client-oriented organization that demonstrates care, anticipation of client needs, attention to detail, distinctive excellence, and client support with care and clarity. We aim to design and deliver services that enable us to exceed client expectations, providing enriching holidays of the highest standard. We strive for sustainable tourism that enhances the quality of life of local communities in India.", "items": [ "Anticipating and Exceeding Traveler Needs", "Pioneering Sustainable & Green Tourism in India", "Empowering Local Communities via Travel", "Integrating User-Friendly Booking Technology" ], "images": [ "https://images.unsplash.com/photo-1593693397690-362cb9666fc2?auto=format&fit=crop&w=800&q=80", "https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?auto=format&fit=crop&w=600&q=80" ] }, "history": { "title": "Our Strength & Team", "description": "Supported by a dedicated team of experts—including tourism experts, quality controllers, R&D personnel, tour planners, ticketing agents, travel guides, and drivers—we maintain excellent services. We strive hard to maintain friendly relations by providing an unforgettable and happy experience. We offer a wide choice of customized packages with competitive prices and absolutely no hidden charges.", "items": [ "Competitive Prices & No Hidden Charges", "Highly Experienced Tour Planners & Guides", "Best Transport & Quality Hotel Services", "24/7 Ground Coordination & Care" ], "images": [ "https://images.unsplash.com/photo-1605649487212-47bdab064df7?auto=format&fit=crop&w=800&q=80", "https://images.unsplash.com/photo-1506461883276-594a12b11db3?auto=format&fit=crop&w=600&q=80" ] }, "howWeWork": { "title": "How We Do Work", "subtitle": "Being a quality-oriented organization, we provide a wide array of high-standard services following the guidelines of the travel industry. Excellence, quality, and comfort are our topmost priorities.", "videoImage": "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80", "videoUrl": "https://www.youtube.com/watch?v=BbrdQLqGUp0" } }', '9810140121', 'G-9R0JL5K333', 'GTM-W225BT8G', 28.61017854877562, 77.0760841189022) ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "name" = EXCLUDED."name", "tagline" = EXCLUDED."tagline", "website" = EXCLUDED."website", "phones" = EXCLUDED."phones", "email" = EXCLUDED."email", "address" = EXCLUDED."address", "timezone" = EXCLUDED."timezone", "schedule" = EXCLUDED."schedule", "exceptions" = EXCLUDED."exceptions", "socialMedia" = EXCLUDED."socialMedia", "certifications" = EXCLUDED."certifications", "about" = EXCLUDED."about", "whatsappNumber" = EXCLUDED."whatsappNumber", "googleAnalytics" = EXCLUDED."googleAnalytics", "googleTagManager" = EXCLUDED."googleTagManager", "latitude" = EXCLUDED."latitude", "longitude" = EXCLUDED."longitude";

