INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (1, 'Weekend Warrior', 'Truly Unforgettable Journey Through the Mother of India Travel and Tours...', 5, 'Golden Triangle Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (2, 'Justine Doinog', 'I recently had the pleasure of joining the Golden Triangle Tour organized by Mother India Tour Agency, and it was an absolutely delightful experience! From start to finish, everything was meticulously planned and well-executed.', 5, 'Golden Triangle Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (3, 'Ralph Marion Gay-ya', 'Our India tour was amazing because of the tour package we availed from Mother India. Our driver Nawab and Mr Jatin is very nice and hospitable. They made sure everything is going well during our trip. Thanks for this trip Mother India!', 5, 'India Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (4, 'Bibiana Parecki', 'I would like to thank Mother India Tour Travels for making our trip to India an unforgettable one. They stayed with us all the time and made us feel safe. They very kind and professional, we highly recommend them.', 5, 'India Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (5, 'Steph Tua', 'Mother India Tours Travel made an exceptional tour arrangement for us for 7 days and 6 nights. It is our first time in India and we are very impressed with the country''s history and culture. Our driver Nawab and Mr Jatin (owner) welcomed us to the airport and made sure everything was going well all throughout our stay in India. Will definitely visit this country again and contact Jatin for our future plans in India.', 5, 'India Tour 7N/8D', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (6, 'Mahendra Kumar Sahu', 'Extraordinary place and good service from Mother India Tour Travels, go for it. It was a great and smooth trip planned by Mother India Tour Travels. Enjoyed a lot, they made sure we cover all the places.', 5, 'Rajasthan Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";
INSERT INTO "Testimonial" ("id", "reviewer", "review", "rating", "package", "source") VALUES (7, 'Anonymous', 'Very well organized custom tour of Rajasthan. Always quick replies and fair price (compared to 2 other companies). Our driver Sachin was very courteous and drove us safely for 8 days. Highly recommended.', 5, 'Rajasthan Tour', 'Google') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "reviewer" = EXCLUDED."reviewer", "review" = EXCLUDED."review", "rating" = EXCLUDED."rating", "package" = EXCLUDED."package", "source" = EXCLUDED."source";

