INSERT INTO "SiteConfig" ("id", "siteName", "domain", "navigation", "homeTitle", "homeDescription", "ogImage", "crossLinkingRules", "urlStructure", "seoPrinciples", "custom404ImageUrl") VALUES (1, 'Mother India Tour Travels', 'https://www.motherindiatourtravels.com', '{"main":[{"label":"Home","url":"/"},{"label":"Destinations","url":"/destinations"},{"label":"Packages","url":"/packages"},{"label":"Categories","url":"/categories","children":[{"label":"Domestic Tours","url":"/categories/domestic-tour-packages"},{"label":"International Tours","url":"/categories/international-tour-packages"},{"label":"Honeymoon Tours","url":"/categories/honeymoon-tour-packages"},{"label":"Family Tours","url":"/categories/family-tour-packages"},{"label":"Spiritual Tours","url":"/categories/spiritual-tour-packages"},{"label":"Wildlife Tours","url":"/categories/wildlife-tour-packages"},{"label":"Beach Tours","url":"/categories/beach-tour-packages"},{"label":"Luxury Tours","url":"/categories/luxury-tour-packages"},{"label":"Budget Tours","url":"/categories/budget-tour-packages"},{"label":"Weekend Tours","url":"/categories/weekend-tour-packages"}]},{"label":"India","url":"/india","children":[{"label":"Delhi","url":"/india/delhi"},{"label":"Rajasthan","url":"/india/rajasthan"},{"label":"Uttar Pradesh","url":"/india/uttar-pradesh"},{"label":"Kerala","url":"/india/kerala"},{"label":"Himachal Pradesh","url":"/india/himachal-pradesh"},{"label":"Uttarakhand","url":"/india/uttarakhand"},{"label":"Jammu & Kashmir","url":"/india/jammu-kashmir"},{"label":"West Bengal","url":"/india/west-bengal"},{"label":"Goa","url":"/india/goa"}]},{"label":"International","url":"/countries","children":[{"label":"Nepal","url":"/countries/nepal"},{"label":"Thailand","url":"/countries/thailand"},{"label":"Malaysia","url":"/countries/malaysia"},{"label":"Dubai (UAE)","url":"/countries/uae"}]},{"label":"Blog","url":"/blog"},{"label":"About","url":"/about"},{"label":"Contact","url":"/contact"}]}', 'Mother India Tour Travels | Best Travel Agency in Delhi', 'Discover India with Mother India Tour Travels – the best travel agency in Delhi. Affordable & customized tour packages for domestic and international destinations.', 'https://i.postimg.cc/CMvnKFqV/Whats-App-Image-2025-08-13-at-17-36-07-6265f9e0.jpg', '{"package → destinations":"package.destination_ids[] → destinations[id]","package → states":"ALL states whose cities appear in destination_ids (multi-state packages appear in ALL their states)","package → countries":"package.country_id + any international destinations","package → categories":"package.category_ids[] → categories[id]","destination.package_ids":"reverse: packages that visit this destination","state.package_ids":"reverse: packages that visit ANY city in this state","country.package_ids":"reverse: packages for this country","category.package_ids":"reverse: packages tagged with this category"}', '{"/":"Homepage","/packages":"All packages listing","/packages/{slug}":"Package page with duration variants (tabs)","/destinations":"All destinations listing","/destinations/{slug}":"Destination page + packages to it","/categories/{slug}":"Category listing page","/india/{state-slug}":"State page","/countries/{slug}":"Country page","/blog/{slug}":"Blog post","/search?q=":"Search — noindex"}', '["Duration variants (4D/5D/6D) on ONE package page → no keyword cannibalization","New package URL only when destination combination changes significantly","Category pages → informational keywords (''honeymoon tour packages'')","Destination pages → ''X tour'', ''visit X'' keywords","Package pages → ''X tour package'', ''X itinerary'' keywords"]', '') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "siteName" = EXCLUDED."siteName", "domain" = EXCLUDED."domain", "navigation" = EXCLUDED."navigation", "homeTitle" = EXCLUDED."homeTitle", "homeDescription" = EXCLUDED."homeDescription", "ogImage" = EXCLUDED."ogImage", "crossLinkingRules" = EXCLUDED."crossLinkingRules", "urlStructure" = EXCLUDED."urlStructure", "seoPrinciples" = EXCLUDED."seoPrinciples", "custom404ImageUrl" = EXCLUDED."custom404ImageUrl";
